import{c as l,a7 as r,y as h,B as e,v as t,D as a}from"./chunks/framework.3cjvm90C.js";const $=JSON.parse('{"title":"REINFORCE++：一种简单高效的大型语言模型对齐方法","description":"介绍REINFORCE++算法如何融合PPO优化技术同时消除Critic网络实现高效对齐","frontmatter":{"title":"REINFORCE++：一种简单高效的大型语言模型对齐方法","description":"介绍REINFORCE++算法如何融合PPO优化技术同时消除Critic网络实现高效对齐"},"headers":[],"relativePath":"rlhf/paper/reinforce_pp.md","filePath":"rlhf/paper/reinforce_pp.md","lastUpdated":1782448598000}'),n={name:"rlhf/paper/reinforce_pp.md"};function p(d,i,o,_,s,c){return r(),h("div",null,[...i[0]||(i[0]=[e('<h1 id="reinforce-一种简单高效的大型语言模型对齐方法" tabindex="-1">REINFORCE++：一种简单高效的大型语言模型对齐方法 <a class="header-anchor" href="#reinforce-一种简单高效的大型语言模型对齐方法" aria-label="Permalink to “REINFORCE++：一种简单高效的大型语言模型对齐方法”">​</a></h1><h2 id="摘要" tabindex="-1">摘要 <a class="header-anchor" href="#摘要" aria-label="Permalink to “摘要”">​</a></h2><p>基于人类反馈的强化学习（RLHF）已成为对齐大型语言模型与人类偏好的关键方法，通过近端策略优化（PPO）、直接偏好优化（DPO）、REINFORCE 留一法（RLOO）、ReMax 和组相对策略优化（GRPO）等方法实现了快速算法演进。我们提出 REINFORCE++，这是经典 REINFORCE 算法的增强变体，融合了 PPO 的关键优化技术同时消除了 Critic 网络的需求。REINFORCE++实现了三个主要目标：</p><p>（1）简洁性</p><p>（2）增强的训练稳定性</p><p>（3）降低计算开销。</p><p>通过大量实证评估，我们证明 REINFORCE++相比 GRPO 具有更优的稳定性，相比 PPO 具有更高的计算效率，同时保持可比性能。实现代码已开源： <a href="https://github.com/OpenRLHF/OpenRLHF%E3%80%82" target="_blank" rel="noreferrer">https://github.com/OpenRLHF/OpenRLHF。</a></p><h2 id="_1-引言" tabindex="-1">1 引言 <a class="header-anchor" href="#_1-引言" aria-label="Permalink to “1 引言”">​</a></h2><p>大型语言模型（LLMs）的快速发展显著提升了其生成连贯、上下文相关且类人文本的能力。然而，将这些模型与人类偏好对齐仍然面临关键挑战，因为模型可能生成与用户意图或伦理准则不符的输出。基于人类反馈的强化学习（RLHF）通过将人类偏好纳入训练过程，已成为解决这一挑战的主要方法。</p><p>该领域经历了显著的算法创新，从基础性的近端策略优化（PPO）到最近的直接偏好优化（DPO）、REINFORCE 留一法（RLOO）、ReMax 和组相对策略优化（GRPO）。PPO 虽然有效，但需要 Critic 网络从而引入额外计算开销。而 GRPO 等新方法虽然解决了特定优化挑战，但可能引入复杂性和不稳定性。</p><p>本文提出 REINFORCE++，这是经典 REINFORCE 算法的新变体，集成了 PPO 的关键优化技术同时无需 Critic 网络。我们的方法围绕三个主要目标设计：</p><p>● 简洁性：基于简单的 REINFORCE 框架，最小化实现复杂度</p><p>● 训练稳定性：通过 Token 级 KL 惩罚、PPO-Clip 损失和标准化优势更新确保鲁棒训练动态</p><p>● 效率：移除 Critic 网络降低计算开销，适合大规模应用</p><p>通过大量实证评估，我们证明 REINFORCE++在显著降低计算需求的同时实现了具有竞争力的对齐性能。主要贡献包括：</p><p>● 将 PPO 启发技术创新性地集成到 REINFORCE 框架</p><p>● 在通用和领域专用数据集上的全面评估</p><p>● 开源实现以促进研究和应用</p><h2 id="_2-背景" tabindex="-1">2 背景 <a class="header-anchor" href="#_2-背景" aria-label="Permalink to “2 背景”">​</a></h2><h3 id="_2-1-基于人类反馈的强化学习" tabindex="-1">2.1 基于人类反馈的强化学习 <a class="header-anchor" href="#_2-1-基于人类反馈的强化学习" aria-label="Permalink to “2.1 基于人类反馈的强化学习”">​</a></h3><p>基于人类反馈的强化学习（RLHF）框架包含三个核心组件：</p><ol><li><p>监督微调（SFT）：在人类标注的提示-响应数据集上对预训练语言模型进行微调，建立基线策略（$\\pi_{\\text{SFT} }$）。该阶段旨在确保模型具备基本的指令遵循能力。</p></li><li><p>奖励建模：通过收集人类对模型输出的排序数据（例如对同一提示的不同响应进行偏好排序），训练奖励模型 $r_{\\phi}(x, y)$ 来量化生成内容的质量。奖励模型需满足以下特性：</p><ul><li>对高质量输出的高奖励预测</li><li>对有害/低质量输出的低奖励预测</li><li>对语义相似输出的奖励平滑性</li></ul></li><li><p>策略优化：使用强化学习算法优化语言模型策略 $\\pi_{\\theta}$，使其最大化奖励模型的预测值。优化目标可形式化为： $$ \\max_{\\theta} \\mathbb{E}<em>{x \\sim \\mathcal{D}, y \\sim \\pi</em>{\\theta}(\\cdot|x)} \\left[ r_{\\phi}(x, y) \\right] - \\beta \\cdot \\mathbb{D}<em>{\\text{KL} } \\left[ \\pi</em>{\\theta}(y|x) | \\pi_{\\text{SFT} }(y|x) \\right] $$</p><p>其中 $\\beta$ 为 KL 散度惩罚系数，用于约束策略更新幅度。</p></li></ol><h3 id="_2-2-reinforce-算法" tabindex="-1">2.2 REINFORCE 算法 <a class="header-anchor" href="#_2-2-reinforce-算法" aria-label="Permalink to “2.2 REINFORCE 算法”">​</a></h3><p>作为策略梯度方法的奠基性算法， REINFORCE 通过以下四步实现优化：</p>',24),t("ol",null,[t("li",null,"轨迹采样：从当前策略 $\\pi_{\\theta}$ 生成完整响应序列"),t("li",null,"回报计算：通过奖励模型评估生成序列的累积回报"),t("li",null,[a("策略梯度估计：使用蒙特卡洛方法估计梯度： $$\\nabla_{\\theta}J(\\theta) = \\mathbb{E}"),t("em",{t:""},"{\\pi}\\left[ G"),a(" \\nabla_{\\theta}\\log\\pi_{\\theta}(a_{t}|s_{t}) \\right]$$ 其中 $G_t$ 表示时间步 $t$ 的折扣累积回报")]),t("li",null,"参数更新：沿梯度方向更新策略参数 $\\theta$")],-1),e('<p>尽管算法结构简单，但 REINFORCE 存在两个主要缺陷：</p><ul><li>高方差：蒙特卡洛估计导致梯度方差较大</li><li>样本效率低：需要完整轨迹才能进行参数更新</li></ul><h3 id="_2-3-rlhf-的挑战" tabindex="-1">2.3 RLHF 的挑战 <a class="header-anchor" href="#_2-3-rlhf-的挑战" aria-label="Permalink to “2.3 RLHF 的挑战”">​</a></h3><p>当前 RLHF 方法面临三大核心挑战：</p><p>● 计算开销：以 PPO 为代表的 Actor-Critic 架构需要同时维护策略网络（actor）和价值网络（critic），显著增加显存占用和计算复杂度。例如在 Llama3-70B 模型训练中， critic 网络会使显存需求增加约 40% 。</p><p>● 训练不稳定性：策略网络和价值网络的相互依赖容易导致训练动态失衡，具体表现为：</p><ul><li>策略网络过度优化奖励导致模式崩溃</li><li>价值网络预测误差累积引发策略震荡</li><li>KL 散度失控导致生成质量下降</li></ul><p>● 可扩展性瓶颈：新兴方法（如 GRPO 的组标准化机制）虽然提升了特定场景的性能，但引入的额外超参数和组件增加了系统复杂度，不利于大规模部署。</p><h2 id="_3-reinforce-改进" tabindex="-1">3 REINFORCE++ 改进 <a class="header-anchor" href="#_3-reinforce-改进" aria-label="Permalink to “3 REINFORCE++ 改进”">​</a></h2><p>REINFORCE++整合了几个关键优化，以增强训练稳定性和效率：</p><h3 id="_3-1-token-级-kl-惩罚" tabindex="-1">3.1 Token 级 KL 惩罚 <a class="header-anchor" href="#_3-1-token-级-kl-惩罚" aria-label="Permalink to “3.1 Token 级 KL 惩罚”">​</a></h3><p>在传统 RLHF 方法中， KL 散度惩罚通常作用于完整序列层面。我们提出 Token 级 KL 惩罚机制，将 KL 约束细化到每个生成 Token：</p><p>$$ r(s_{t},a_{t})=I(s_{t}=[EOS])r(x,y)-\\beta\\cdot KL(t) $$ $$ \\text{KL}(t) = \\log \\left( \\frac{\\pi_{\\text{RL} }^\\theta (a_t | s_t)}{\\pi_{\\text{SFT} } (a_t | s_t)} \\right), $$</p><p>其中：</p><ul><li>$I(s_{t}=[EOS])$ 是指示函数，表示 $t$ 是否为最终 Token，仅在序列结束符位置生效</li><li>$KL(t)=D_{\\text{KL} }\\left(\\pi_{\\theta}(a_t|s_t) | \\pi_{\\text{SFT} }(a_t|s_t)\\right)$ 计算当前策略与 SFT 模型的 Token 级分布差异</li><li>$\\beta$ 为动态调整的惩罚系数</li></ul><p>该设计实现两个关键优势：</p><ol><li>细粒度控制：在生成过程中实时约束策略偏移</li><li>训练稳定性：避免序列后期 KL 散度突然激增</li></ol><h3 id="_3-2-ppo-clip-集成" tabindex="-1">3.2 PPO-Clip 集成 <a class="header-anchor" href="#_3-2-ppo-clip-集成" aria-label="Permalink to “3.2 PPO-Clip 集成”">​</a></h3><p>借鉴 PPO 的 clip 机制，我们将其核心思想融入 REINFORCE 框架：</p>',19),t("p",null,[a("$$ L^{CLIP}(\\theta)=\\mathbb{E}"),t("em",{t:""},"{t}\\left[\\min\\left(r"),a("(\\theta)\\hat{A}"),t("em",{t:""},"{t},\\ \\text{clip}(r"),a("(\\theta),1-\\epsilon,1+\\epsilon)\\hat{A}_{t}\\right)\\right] $$ 其中：")],-1),e('<ul><li>$r_t (\\theta) = \\frac{\\pi_\\theta (a_t | s_t)}{\\pi_{\\text{old} } (a_t | s_t)}$是在新策略与旧策略下，在状态 $s_t$下采取动作 $a_t$的概率比。</li><li>$\\hat{A}_t$ 是 Token $t$ 的估计优势。</li><li>$\\text{clip} (r_t (\\theta), 1 - \\epsilon, 1 + \\epsilon)$ 将概率比限制在 $[1 - \\epsilon, 1 + \\epsilon]$ 范围内，其中 $\\epsilon$ 是一个小的超参数（通常设置为 0.2 左右）。</li></ul><h3 id="_3-3-小批量更新" tabindex="-1">3.3 小批量更新 <a class="header-anchor" href="#_3-3-小批量更新" aria-label="Permalink to “3.3 小批量更新”">​</a></h3><p>为了提高训练效率，我们实现了具有以下特点的小批量更新：</p><ol><li>批量处理：将完整轨迹数据划分块处理 , 小批量（mini-batch）</li><li>多次更新：每个小批量允许多次参数更新 ,显著提升样本利用率</li><li>随机优化：通过随机排列小批量顺序，注入有益噪声以增强泛化能力</li></ol><h3 id="_3-4-奖励归一化与截断" tabindex="-1">3.4 奖励归一化与截断 <a class="header-anchor" href="#_3-4-奖励归一化与截断" aria-label="Permalink to “3.4 奖励归一化与截断”">​</a></h3><p>实施奖励处理三原则：</p><ol><li>标准化： 使用 z-score 消除异常值</li><li>截断：限制奖励值范围</li><li>缩放：应用适当缩放因子</li></ol><h3 id="_3-5-优势归一化" tabindex="-1">3.5 优势归一化 <a class="header-anchor" href="#_3-5-优势归一化" aria-label="Permalink to “3.5 优势归一化”">​</a></h3><p>我们重新定义优势函数并实施标准化：</p><p>$$ A_{t} = r(x, y) - \\beta\\cdot\\sum_{i=t}^{T} KL(i) $$ 标准化流程：</p><ol><li>计算当前批次优势值的均值 $\\mu_A$ 和标准差 $\\sigma_A$</li><li>应用 z-score 变换： $$A_{\\text{normalized} } = \\frac{A - \\mu_A}{\\sigma_A + 10^{-8} }$$</li><li>最终梯度估计量： $$\\nabla_{\\theta}J(\\theta) = \\mathbb{E}\\left[ A_{\\text{normalized} } \\cdot \\nabla_{\\theta}\\log\\pi_{\\theta}(a_t|s_t) \\right]$$</li></ol><p>该设计有效解决梯度幅度波动问题，同时保持策略更新的方向准确性。</p><h2 id="_4-实验设置" tabindex="-1">4 实验设置 <a class="header-anchor" href="#_4-实验设置" aria-label="Permalink to “4 实验设置”">​</a></h2><h3 id="_4-1-实验设计" tabindex="-1">4.1 实验设计 <a class="header-anchor" href="#_4-1-实验设计" aria-label="Permalink to “4.1 实验设计”">​</a></h3><p>使用 Llama3.1-8B-SFT 和 Qwen2.5-7B-Instruct 作为基础模型，在通用领域和数学领域数据集进行评估。</p><h3 id="_4-2-超参数配置" tabindex="-1">4.2 超参数配置 <a class="header-anchor" href="#_4-2-超参数配置" aria-label="Permalink to “4.2 超参数配置”">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Parameter</th><th>Value</th></tr></thead><tbody><tr><td style="text-align:left;">KL Penalty Coefficient (β)</td><td>0.01 (General), 0.001 (Mathematics)</td></tr><tr><td style="text-align:left;">Maximum Samples</td><td>25,000</td></tr><tr><td style="text-align:left;">Samples per Prompt</td><td>4</td></tr><tr><td style="text-align:left;">Rollout Batch Size</td><td>256</td></tr><tr><td style="text-align:left;">Training Batch Size</td><td>128</td></tr><tr><td style="text-align:left;">Actor Learning Rate</td><td>5 ×10 −7</td></tr><tr><td style="text-align:left;">Critic Learning Rate</td><td>9 ×10 −6</td></tr><tr><td style="text-align:left;">Discount Factor (γ)</td><td>1.0</td></tr><tr><td style="text-align:left;">Clip ϵ</td><td>0.2</td></tr></tbody></table><h3 id="_4-3-数据集详情" tabindex="-1">4.3 数据集详情 <a class="header-anchor" href="#_4-3-数据集详情" aria-label="Permalink to “4.3 数据集详情”">​</a></h3><p>我们使用了两个不同的数据集进行评估：</p><ul><li>一般领域：涵盖一般知识和对话主题的多样化提示集合和偏好数据集。</li><li>数学领域：一个专门的数据集和一个闭源数学奖励模型，旨在测试模型在数学情境中的推理和解决问题能力。</li></ul><h2 id="_5-结果分析" tabindex="-1">5 结果分析 <a class="header-anchor" href="#_5-结果分析" aria-label="Permalink to “5 结果分析”">​</a></h2><h3 id="_5-1-训练稳定性" tabindex="-1">5.1 训练稳定性 <a class="header-anchor" href="#_5-1-训练稳定性" aria-label="Permalink to “5.1 训练稳定性”">​</a></h3><p>我们的实验结果表明了几个关键发现：</p><ul><li>一般场景下的 Bradley-Terry 奖励模型： REINFORCE++在防止奖励和输出长度操纵方面表现出比 GRPO 更好的稳定性（图 1）。</li><li>基于规则的奖励模型：在基于规则的奖励场景下， REINFORCE++实现了与 GRPO （组归一化）相当的性能（图 2）。</li><li>数学奖励模型：在数学问题解决场景下， REINFORCE++在每个单位 KL 散度下实现了比 GRPO 更好的奖励增加（图 3）。</li></ul><h3 id="_5-2-计算效率" tabindex="-1">5.2 计算效率 <a class="header-anchor" href="#_5-2-计算效率" aria-label="Permalink to “5.2 计算效率”">​</a></h3><p>在 H100 GPU 上的对比：</p><table tabindex="0"><thead><tr><th>方法</th><th>训练时间</th></tr></thead><tbody><tr><td>PPO</td><td>60 小时</td></tr><tr><td>REINFORCE++</td><td>42 小时</td></tr></tbody></table><h2 id="_6-结论" tabindex="-1">6 结论 <a class="header-anchor" href="#_6-结论" aria-label="Permalink to “6 结论”">​</a></h2><p>REINFORCE++作为 PPO 和 GRPO 的简单高效替代方案，在保持性能的同时显著降低计算需求。未来工作将探索更大规模数据集和复杂对齐场景的应用。</p><h2 id="参考文献" tabindex="-1">参考文献 <a class="header-anchor" href="#参考文献" aria-label="Permalink to “参考文献”">​</a></h2><p>[1] Jian Hu, Xibin Wu, Zilin Zhu, Xianyu, Weixun Wang, Dehao Zhang, and Yu Cao. Openrlhf: An easy-to-use, scalable and high-performance rlhf framework. <em>arXiv preprint arXiv:2405.11143</em>, 2024.</p><p>[2] Ziniu Li, Tian Xu, Yushun Zhang, Yang Yu, Ruoyu Sun, and Zhi-Quan Luo. Remax: A simple, effective, and efficient method for aligning large language models. <em>arXiv preprint arXiv:2310.10505</em>, 2023.</p>',32)])])}const b=l(n,[["render",p]]);export{$ as __pageData,b as default};
